import React, { useState } from 'react';
import { Resizable } from 're-resizable';
import { DraggableCore } from 'react-draggable';
import Experiences from './Experiences'; // Import direct de votre composant Experiences

const WithResizableDraggable = () => {
    const [position, setPosition] = useState({ x: 50, y: 50 });
    const [size, setSize] = useState({
        width: 500,
        height: 600
    });

    const handleDrag = (e: any, data: any) => {
        setPosition({
            x: data.x,
            y: data.y
        });
    };

    return (
        <DraggableCore
            handle=".experiences-handle"
            position={position}
            onDrag={handleDrag}
        >
            <Resizable
                size={size}
                onResizeStop={(e, direction, ref, d) => {
                    setSize(prevSize => ({
                        width: prevSize.width + d.width,
                        height: prevSize.height + d.height
                    }));
                }}
                minWidth={350}
                minHeight={400}
                maxWidth={800}
                maxHeight={800}
                style={{
                    position: 'absolute',
                    zIndex: 10,
                    boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
                }}
                enable={{
                    top: false,
                    right: true,
                    bottom: true,
                    left: false,
                    topRight: false,
                    bottomRight: true,
                    bottomLeft: false,
                    topLeft: false
                }}
            >
                <div
                    className="experiences-container"
                    style={{
                        width: '100%',
                        height: '100%',
                        position: 'relative',
                        border: '2px solid var(--border-color)',
                        borderRadius: 'var(--border-radius)',
                        backgroundColor: 'var(--card-color)'
                    }}
                >
                    <div
                        className="experiences-handle"
                        style={{
                            position: 'absolute',
                            top: 0,
                            left: 0,
                            right: 0,
                            height: '30px',
                            cursor: 'move',
                            backgroundColor: 'var(--primary-color)',
                            opacity: 0.2,
                            zIndex: 20,
                            borderTopLeftRadius: 'var(--border-radius)',
                            borderTopRightRadius: 'var(--border-radius)'
                        }}
                    />
                    <div
                        style={{
                            height: 'calc(100% - 30px)',
                            marginTop: '30px',
                            position: 'relative',
                            overflow: 'hidden'
                        }}
                    >
                        <Experiences experiences={[
                            // Vos données d'expériences en dur pour le debug
                            {
                                experienceId: '1',
                                titre: 'Développeur Web',
                                description: 'Développement d\'applications web',
                                dateDebut: '2022-01-01',
                                dateFin: null,
                                competences: ['React', 'TypeScript', 'Node.js']
                            },
                            {
                                experienceId: '2',
                                titre: 'Concepteur UI/UX',
                                description: 'Design d\'interfaces utilisateur',
                                dateDebut: '2020-06-01',
                                dateFin: '2022-01-01',
                                competences: ['Figma', 'Adobe XD', 'Design Thinking']
                            }
                        ]} />
                    </div>
                    <div
                        style={{
                            position: 'absolute',
                            bottom: 0,
                            right: 0,
                            width: '15px',
                            height: '15px',
                            cursor: 'se-resize',
                            backgroundColor: 'var(--primary-color)',
                            opacity: 0.3,
                            zIndex: 20,
                            borderBottomRightRadius: 'var(--border-radius)'
                        }}
                    />
                </div>
            </Resizable>
        </DraggableCore>
    );
};

export default WithResizableDraggable;
